mapper.select:
SELECT COUNT(r.id) FROM review r LEFT JOIN user u ON r.user_id = u.id
AND r.review_status = 'ACTIVE'
AND (LOWER(r.title) LIKE CONCAT('%', LOWER(#{keyword}), '%') OR LOWER(r.address) LIKE CONCAT('%', LOWER(#{keyword}), '%'))
AND LOWER(r.content) LIKE CONCAT('%', LOWER(#{keyword}), '%')
AND (
EXISTS ( SELECT 1 FROM review_attribute pa WHERE pa.review_id = r.id AND pa.type = 'PRO' AND pa.content IN
#{p}
)
OR
EXISTS ( SELECT 1 FROM review_attribute ca WHERE ca.review_id = r.id AND ca.type = 'CON' AND ca.content IN
#{c}
)
)

SELECT r.id, r.title, r.content, r.address, r.user_id, u.login_id AS loginId, r.point, r.review_status, r.like_count, r.view_count, r.created_at, r.updated_at,
(SELECT GROUP_CONCAT(pa.content) FROM review_attribute pa WHERE pa.review_id = r.id AND pa.type = 'PRO') AS prosStr,
COALESCE( (SELECT f.file_path FROM file f WHERE f.target_id = r.id AND f.target_type = 'REVIEW_THUMB' LIMIT 1), (SELECT f.file_path FROM file f WHERE f.target_id = r.id AND f.target_type = 'REVIEW' LIMIT 1) ) AS filePath
FROM review r LEFT JOIN user u ON r.user_id = u.id
AND r.review_status = 'ACTIVE'
AND (LOWER(r.title) LIKE CONCAT('%', LOWER(#{keyword}), '%') OR LOWER(r.address) LIKE CONCAT('%', LOWER(#{keyword}), '%'))
AND LOWER(r.content) LIKE CONCAT('%', LOWER(#{keyword}), '%')
AND (
EXISTS ( SELECT 1 FROM review_attribute pa WHERE pa.review_id = r.id AND pa.type = 'PRO' AND pa.content IN
#{p}
)
OR
EXISTS ( SELECT 1 FROM review_attribute ca WHERE ca.review_id = r.id AND ca.type = 'CON' AND ca.content IN
#{c}
)
)
ORDER BY r.id DESC
LIMIT #{pageable.pageSize} OFFSET #{pageable.offset}

