mapper.select:
SELECT r.id, r.title, r.address, r.user_id, u.login_id AS loginId, r.point, r.review_status, r.created_at,
(SELECT f.file_path FROM file f JOIN certification c ON f.target_id = c.id WHERE c.review_id = r.id AND f.target_type = 'CERTIFICATION' ORDER BY c.id DESC LIMIT 1) AS filePath FROM review r LEFT JOIN user u ON r.user_id = u.id
WHERE r.review_status = 'PENDING' ORDER BY r.id DESC LIMIT #{pageSize} OFFSET #{offset}

